/**
 * Vendored GSAP 3.15.0（dist/gsap.min.js）—— base64 内嵌。
 *
 * 为什么内嵌而不走 CDN / npm 依赖：
 *   - 控制台是 loopback-only（127.0.0.1）的隐私敏感工具，绝不能向第三方 CDN 发请求
 *     （会外泄「该用户打开了控制台」且离线即坏）。
 *   - 不引入整个 gsap npm 包（~3.4MB，与项目「轻量按需」理念冲突）；只 vendoring 单个
 *     dist/gsap.min.js（~71KB），base64 化以便 tsup 单文件打包、运行时由
 *     /vendor/gsap.min.js 路由提供（见 web/server.ts）。
 *   - GSAP 标准免费授权（GreenSock）；许可证头保留在压缩源码内。
 *
 * 升级：npm pack gsap@<ver> → 取 package/dist/gsap.min.js → 重新 base64 替换下串 + 改版本号。
 */
export const GSAP_VERSION = "3.15.0";

/** GSAP min 源码的 base64（server 解码后以 application/javascript 提供）。 */
export const GSAP_MIN_JS_BASE64 =
  "";
